DWORD RmJoinSession(
[out] DWORD          *pSessionHandle,
[in]  const WCHAR [] strSessionKey);

typedef struct _RM_FILTER_INFO {   RM_FILTER_ACTION  FilterAction;   RM_FILTER_TRIGGER FilterTrigger;   DWORD             cbNextOffset;   union {
LPWSTR            strFilename;     RM_UNIQUE_PROCESS Process;
LPWSTR            strServiceShortName;   };
} RM_FILTER_INFO, *PRM_FILTER_INFO;

typedef struct _RM_PROCESS_INFO {   RM_UNIQUE_PROCESS Process;
WCHAR             strAppName[CCH_RM_MAX_APP_NAME + 1];
WCHAR             strServiceShortName[CCH_RM_MAX_SVC_NAME + 1];   RM_APP_TYPE       ApplicationType;
ULONG             AppStatus;   DWORD             TSSessionId;   BOOL              bRestartable;
} RM_PROCESS_INFO, *PRM_PROCESS_INFO;

DWORD RmGetList(
[in]                DWORD              dwSessionHandle,   [out]               UINT               *pnProcInfoNeeded,   [in, out]           UINT               *pnProcInfo,
[in, out, optional] RM_PROCESS_INFO [] rgAffectedApps,   [out]               LPDWORD            lpdwRebootReasons);

DWORD RmRestart(
[in]           DWORD                    dwSessionHandle,                  DWORD                    dwRestartFlags,
[in, optional] RM_WRITE_STATUS_CALLBACK fnStatus);

DWORD RmRemoveFilter(
[in]           DWORD             dwSessionHandle,   [in, optional] LPCWSTR           strModuleName,   [in, optional] RM_UNIQUE_PROCESS *pProcess,
[in, optional] LPCWSTR           strServiceShortName);

DWORD RmShutdown(
[in]           DWORD                    dwSessionHandle,   [in]           ULONG                    lActionFlags,
[in, optional] RM_WRITE_STATUS_CALLBACK fnStatus);
